// APB subordinate port example completely generated by LLM with /skills/systemc-tools

#ifndef COPILOT_APB_PORT_H
#define COPILOT_APB_PORT_H

#include "sct_common.h"
#include <systemc.h>

template<unsigned ADDR_W, unsigned DATA_W>
struct apb_port : public sc_module {
    static_assert(ADDR_W > 0, "APB address width must be positive");
    static_assert(DATA_W > 0, "APB data width must be positive");
    static_assert(DATA_W % 8 == 0, "APB data width must be a multiple of 8");

    static const unsigned STRB_W = DATA_W / 8;
    static const unsigned STATE_IDLE = 0;
    static const unsigned STATE_REQUEST = 1;
    static const unsigned STATE_RESPONSE = 2;
    static const unsigned STATE_COMPLETE = 3;

    struct Req {
        sct_uint<ADDR_W> addr;
        bool write;
        sct_uint<DATA_W> wdata;
        sct_uint<STRB_W> wstrb;

        Req() : addr(0), write(false), wdata(0), wstrb(0) {}

        bool operator==(const Req& rhs) const {
            return addr == rhs.addr && write == rhs.write &&
                   wdata == rhs.wdata && wstrb == rhs.wstrb;
        }

        friend std::ostream& operator<<(std::ostream& os, const Req& value) {
            os << "addr=" << value.addr << " write=" << value.write
               << " wdata=" << value.wdata << " wstrb=" << value.wstrb;
            return os;
        }

        friend void sc_trace(sc_trace_file* file, const Req& value,
                             const std::string& name) {
            sc_trace(file, value.addr, name + ".addr");
            sc_trace(file, value.write, name + ".write");
            sc_trace(file, value.wdata, name + ".wdata");
            sc_trace(file, value.wstrb, name + ".wstrb");
        }
    };

    struct Resp {
        sct_uint<DATA_W> rdata;
        bool slverr;

        Resp() : rdata(0), slverr(false) {}

        bool operator==(const Resp& rhs) const {
            return rdata == rhs.rdata && slverr == rhs.slverr;
        }

        friend std::ostream& operator<<(std::ostream& os, const Resp& value) {
            os << "rdata=" << value.rdata << " slverr=" << value.slverr;
            return os;
        }

        friend void sc_trace(sc_trace_file* file, const Resp& value,
                             const std::string& name) {
            sc_trace(file, value.rdata, name + ".rdata");
            sc_trace(file, value.slverr, name + ".slverr");
        }
    };

    sc_in_clk PCLK{"PCLK"};
    sc_in<bool> PRESETn{"PRESETn"};

    sc_in<sct_uint<ADDR_W>> PADDR{"PADDR"};
    sc_in<bool> PSEL{"PSEL"};
    sc_in<bool> PENABLE{"PENABLE"};
    sc_in<bool> PWRITE{"PWRITE"};
    sc_in<sct_uint<DATA_W>> PWDATA{"PWDATA"};
    sc_in<sct_uint<STRB_W>> PSTRB{"PSTRB"};

    sc_out<bool> PREADY{"PREADY"};
    sc_out<sct_uint<DATA_W>> PRDATA{"PRDATA"};
    sc_out<bool> PSLVERR{"PSLVERR"};

    sct_initiator<Req> req_init{"req_init"};
    sct_target<Resp> resp_target{"resp_target"};

    SC_HAS_PROCESS(apb_port);

    explicit apb_port(const sc_module_name& name) : sc_module(name) {
        req_init.clk_nrst(PCLK, PRESETn);
        resp_target.clk_nrst(PCLK, PRESETn);

        SCT_CTHREAD(apb_thread, PCLK, SCT_CMN_TRAITS::CLOCK);
        req_init.addTo(sensitive);
        resp_target.addTo(sensitive);
        async_reset_signal_is(PRESETn, false);
    }

    void apb_thread() {
        Req req_reg;
        Resp resp;
        sct_uint<2> state;
        bool req_done;
        bool resp_done;

        req_init.reset_put();
        resp_target.reset_get();

        req_reg = Req();
        resp = Resp();
        state = STATE_IDLE;
        PREADY = false;
        PRDATA = 0;
        PSLVERR = false;
        wait();

        while (true) {
            PREADY = false;
            req_done = false;
            resp_done = false;

            switch (state) {
            case STATE_IDLE:
                // Capture APB setup phase. Address/control must remain stable in enable.
                if (PSEL.read() && !PENABLE.read()) {
                    req_reg.addr = PADDR.read();
                    req_reg.write = PWRITE.read();
                    req_reg.wdata = PWDATA.read();
                    req_reg.wstrb = PSTRB.read();
                    state = STATE_REQUEST;
                }
                break;

            case STATE_REQUEST:
                // Hold PREADY low until the internal request channel accepts transfer.
                if (PSEL.read() && PENABLE.read()) {
                    req_done = req_init.put(req_reg);
                    if (req_done) {
                        state = STATE_RESPONSE;
                    }
                } else if (!PSEL.read()) {
                    state = STATE_IDLE;
                }
                break;

            case STATE_RESPONSE:
                // Complete both reads and writes only after target-side response arrives.
                resp_done = resp_target.get(resp);
                if (resp_done) {
                    PRDATA = resp.rdata;
                    PSLVERR = resp.slverr;
                    state = STATE_COMPLETE;
                }
                break;

            case STATE_COMPLETE:
                PREADY = PSEL.read() && PENABLE.read();
                state = STATE_IDLE;
                break;

            default:
                state = STATE_IDLE;
                break;
            }

            wait();
        }
    }
};

#endif // COPILOT_APB_PORT_H
